var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"전부 사라졌군요. 도시도, 그 두 사람도.","JPN":"全部消えましたね。都市も、あの二人も。","ENG":"It's all gone. The city, and those two.","TWN":"全都消失了，包括城市和那兩個人。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"관리국의 지도와 지형 정보도 대조할 수 있게 됐어요.","JPN":"管理局の地図と地形情報も照合できるようになりました。","ENG":"We can now compare the terrain with the Administration's map.","TWN":"管理局的地圖和地形資料也恢復正常了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"여긴 이제 평범한 도시 외곽 지역이에요.","JPN":"もう普通の都市の郊外に戻りましたね。","ENG":"This is just an ordinary suburb now.","TWN":"這裡現在就只是個普通的郊區。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"……알렌 선생님, 나쁜 사람은 아니라고 생각했어.","JPN":"……アレン先生、悪い人じゃないと思ってたよ。","ENG":"...I thought Mr. Birmingham wasn't a bad guy.","TWN":"……我原本不覺得艾倫老師是壞人，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"오히려 오랜만에 말이 통하는 사람을 만났다고, 친해질 수도 있겠다고 생각했는데…….","JPN":"むしろ久しぶりに話が通じる人に会えて、親しくなれると思ったのに……","ENG":"If anything, I thought I could make friends with him for a change…","TWN":"反而覺得好不容易遇到一個談得來的人，應該可以成為好朋友吧……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"회장, 정말 알렌 선생님이 주시윤 선배를 납치한 걸까?","JPN":"会長、本当にアレン先生がアキヤマ先輩を攫ったと思う？","ENG":"Yen, do you really think the Prof abducted Shiyoon?","TWN":"會長，綁架周時雲前輩的真的是艾倫老師嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지금 상황만으로는, 네. 가능성이 높군요.","JPN":"今の状況だけを考えると、はい、その可能性が高いですね。","ENG":"Given what I've seen thus far… Yes. That seems most likely.","TWN":"照目前的情況來看，是的，這個可能性很高。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"뭐해? 멍하니 서서.","JPN":"何してるの？　ぼーっとしちゃって。","ENG":"What are you doing? Don't just stand there.","TWN":"傻愣在這裡做什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"쫓아가야지?","JPN":"追いかけるんでしょ？","ENG":"We should go after him.","TWN":"快追啊！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어? 뭐라고?","JPN":"え、なんて？","ENG":"Huh? What?","TWN":"嗯？你說什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"뒤쫓자니까. 여기서 포기할 생각이었으면 부사장님한테 욕 먹을 각오도 안 했어.","JPN":"追いかけようよ。\\nここで諦めるつもりなら、副社長に大目玉をくらう覚悟もしなかったよ。","ENG":"I said we should go after him. I wouldn't have risked getting a mouthful from the Vice President if I was going to give up this early.","TWN":"我說追上去！我可是冒著被副總飆罵的風險來的，怎麼可能就這樣放棄！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하지만 쫓아가고 싶어도 방법이 없잖아.","JPN":"でも追いかけたくても方法がないよ。","ENG":"I wish I could, but there's no way to pursue him.","TWN":"但是要怎麼追？有什麼方法？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"후훗. 방법이라는 건 찾아 보면 다 있기 마련이야.","JPN":"フフッ、方法なんて探せばいくらでもあるものだよ。","ENG":"Heh. Where there is a will, there's a way.","TWN":"哈哈～方法這東西不是找就有的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"시그마, 내 말 들려?","JPN":"シグマ、聞こえる？","ENG":"Sigma, can you hear me?","TWN":"西格瑪，有聽見我的聲音嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"응! 아빠 말대로 언니 연락을 기다리고 있었단 말씀!","JPN":"うん！　パパの言うとおり、シズカお姉ちゃんの連絡を待ってたよ！","ENG":"Yes! I've been waiting to hear from you, just as daddy told me!","TWN":"有聽到！我有乖乖聽爸爸的話等姊姊聯絡我！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"좋아. 부탁할게. 네 도움이 필요해.","JPN":"よし、お願いね。あなたの助けが必要なの。","ENG":"Great. Listen. I need your help.","TWN":"很棒！我現在需要你的幫忙！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"저건…… 차원함선?","JPN":"あれは……次元艦船？","ENG":"Is that… a dimensional ship?","TWN":"那個是……次元艦船？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 구형이지만 확실히 차원 강습함이에요.","JPN":"はい、旧型ですが間違いなく次元強襲艦です。","ENG":"Yes. It's an older model, but that's definitely an interdimensional assault ship.","TWN":"對，雖然是舊型的，但確實是次元強襲艦。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이렇게 빨리 나타났다는 건…… 인근에서 대기하고 있었다는 뜻이겠죠.","JPN":"こんなに早く現れたということは……近くで待機していたのでしょう。","ENG":"If it appeared so quickly… that must mean it was on standby in the vicinity.","TWN":"可以這麼快就出現……應該是從剛才就一直在附近待命吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"시그마, 방금 여기서 차원간 이동이 발생한 것 같아.","JPN":"シグマ、ちょうど今ここで次元間移動が発生したみたい。","ENG":"Sigma, there seems to have been an interdimensional jump here just now.","TWN":"西格瑪，剛才這裡好像有發生次元間移動，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"다이브 좌표를 역산해서 쫓아갈 수 있겠어?","JPN":"ダイブ座標を逆算して追跡できる？","ENG":"Do you think you can deduce the dive coordinates and follow them?","TWN":"你可以演算出躍入座標追上去吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"물론이지. 그런 계산은 다섯 손가락만 있어도 간단하다구.","JPN":"もちろん。それぐらい指五本あればすぐ計算できるよ。","ENG":"Of course. All you need is five fingers to run that calculation.","TWN":"當然，我用一根手指頭也算得出來！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"짜잔~! 계산 완료!","JPN":"ジャーン！　計算完了！","ENG":"Tada! Calculation complete!","TWN":"鏘鏘～！算好囉！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"좋아, 다들 올라타. 2차전을 하러 가야지.","JPN":"よし、みんな乗って。2回戦だよ。","ENG":"Great. Hop on, everyone. It's time for round two.","TWN":"很好！大家上船吧！下一場戰鬥要開始囉！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"기다려! 저건 코핀함이잖아!","JPN":"まって！　あれはコフィン艦じゃない？","ENG":"Wait! That's Coffin, isn't it?","TWN":"先等等！那不是科芬艦嗎！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"시그마까지 속여서 무단으로 출격시킨 거야? 너 이러다 회사에서 잘리면 어쩌려고?","JPN":"シグマまで騙して無断で出撃させたの？　これで首になったらどうするの！？","ENG":"Did you trick Sigma into bringing that here? What if you get fired?","TWN":"你還騙西格瑪一起出擊嗎？萬一被公司抓到你可能會被裁員欸！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"하아……. 걱정은 고마운데 아직도 날 너무 모르네.","JPN":"はあ、心配してくれるのはありがたいけど、私のことをまだわかってないみたいね。","ENG":"Ugh… I appreciate your concern, but you really don't know me at all.","TWN":"哈……謝謝你還為我擔心，但你似乎還不是很認識我。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"설마 내가 너처럼 아무 생각 없이 사고를 쳤겠어?","JPN":"まさかこの私が、あなたみたいに何も考えずに行動したと思う？","ENG":"Did you think I'd just make trouble without a plan like you?","TWN":"你以為我跟你一樣有勇無謀嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"마침 연락이 왔네. 받아 봐.","JPN":"ちょうど連絡が来たわ。出てみて。","ENG":"Ah, perfect timing. Pick up.","TWN":"打來得正好！給你接！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"여, 여보세요?","JPN":"も、もしもし？","ENG":"H-hello?","TWN":"喂…你好？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 미나 양. 몸은 좀 어떤가.","JPN":"おお、ミナ君。体の調子はどうだ？","ENG":"Oh, Mina. How are you feeling?","TWN":"米娜～最近身體還好嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이 목소리는…… 사장님?","JPN":"この声は……社長？","ENG":"Huh? That voice... Boss?","TWN":"這個聲音是…… 老闆？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래. 나일세.","JPN":"ああ、私だ。","ENG":"Yup. It's me.","TWN":"對啊，我是老闆。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"시간이 없으니 짧게 이야기하지.","JPN":"時間がないから手短に話そう。","ENG":"Let me cut to the chase since we're strapped for time.","TWN":"時間不多，我們就長話短說吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"사실 나는 주시윤 군을 납치한 범인들이 자네에게도 접근할 거라고 추측했다네.","JPN":"実は私は、アキヤマ君を攫っていった犯人が君にも近づくと推測していた。","ENG":"I had a hunch that Shiyoon's kidnappers would try to approach you as well.","TWN":"是這樣的，我早就知道綁架周時雲的人會找上你，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래서 서윤 양에게 자네 곁을 지켜 달라고 부탁했지.","JPN":"だからシズカ君に君のそばで守ってほしいと頼んでおいた。","ENG":"That's why I asked Yoon to keep an eye on you.","TWN":"所以特別拜託徐芸在你身邊保護你。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그게…… 정말이야?","JPN":"……本当に？","ENG":"Is this… for real?","TWN":"你是說……真的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그럼 물론이지.","JPN":"ええ、もちろん。","ENG":"Of course.","TWN":"那還用說！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"우리가 그렇게 친한 사이도 아닌데 굳이 내 자리까지 걸고 널 도와 줄 리 없잖아. 후훗.","JPN":"そんなに親しい仲でもないのに、私が首になるリスクを背負ってまであなたを助けるはずがないでしょ、フフッ。","ENG":"Did you really think I'd stick my neck out for you? We're not that close. Heh.","TWN":"我跟你又不熟，怎麼會沒事好好的小隊長不當來幫你？呵呵～"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"아, 혹시 조금 설렜다면 미안. 그래도 컵라면은 잘 얻어 먹을게.","JPN":"あ、ついときめかせちゃったらごめんね。でも焼きそばパンはちゃんと奢ってもらうから。","ENG":"Oh, sorry if I got you a bit excited. I'll still accept that cup of noodles though.","TWN":"如果你因此覺得感動的話，真是不好意思喔～但泡麵我還是會吃啦～"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"만약 내 추측대로 범인들과 조우한다면, 주시윤 군이 있는 곳을 찾을 단서를 발견할지도 모르지.","JPN":"もし私の推測どおり犯人たちと遭遇するなら、\\nアキヤマ君の居場所の手がかりが見つかるかもしれない。","ENG":"If you can find the culprits as I've guessed, you may be able to find a lead to where they took Shiyoon.","TWN":"若是照我的推測，你遇到犯人的時候，應該就會發現找到周時雲下落的線索，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래서 차원 좌표 역산이 가능한 우리 딸과 코핀 함을 미리 배치해 둔 걸세.","JPN":"それで次元座標の逆算ができるうちの娘とコフィン艦をあらかじめ配置しておいたのだ。","ENG":"That's why I've left my daughter to trace their coordinates along with the Coffin right near you.","TWN":"所以我就先安排好我那會計算次元座標的女兒和科芬艦，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아마 그리로 가면 주시윤 군을 찾을 수 있을 거야.","JPN":"おそらくそこに行けばアキヤマ君を見つけられるだろう。","ENG":"You should be able to find Shiyoon there.","TWN":"這樣就可以立刻出發去找周時雲，事情就是這樣。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐…… 미끼 역할이었다는 건 조금 섭섭하지만…….","JPN":"まあ……囮役だったってことはちょっと悲しいけど……","ENG":"Hmm… I can't say I appreciate being the bait…","TWN":"喔……雖然拿我當誘餌有點難過……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"고마워, 사장님.","JPN":"ありがとう、社長。","ENG":"But thanks Boss.","TWN":"但是謝謝老闆！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음. 아직 고마워하긴 이르지. 자네들을 도울 사원도 같이 보냈으니까.","JPN":"いや、まだ感謝するには早いぞ。君たちを助ける社員も一緒に送ったからな。","ENG":"Hmm. Don't thank me so soon. I've also sent a few employees to assist you.","TWN":"嗯，現在還不是說謝謝的時候，我還派了其他員工去幫你們。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"우릴 도울 사원?","JPN":"助けてくれる社員？","ENG":"To assist us?","TWN":"派其他員工來幫我們？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"도움이 필요한가, 인간 친구들! 세기말 결전병기가 여기 도착했다네!","JPN":"助けが必要か、人間の友よ！　世紀末決戦兵器が只今参ったぞ！","ENG":"Need some help, my human friends? The Ultimate Doomsday Weapon has arrived!","TWN":"我親愛的人類朋友，需要幫忙嗎？世紀末決戰兵器抵達！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_TOUCH"},"C":null,"R":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_22"},{"id":"L31_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"나도! 나도 결전병기야!","JPN":"私も！　私も決戦兵器だよ！","ENG":"Me too! I'm a Doomsday Weapon too!","TWN":"還有我！我也是決戰兵器！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_TOUCH"},"C":null,"R":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_71"},{"id":"L32_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하, 이런 실수를! 결전병기가 두 대나 왔지, 참!","JPN":"ガハハ、吾輩としたことが！　決戦兵器が2機も来たぞ！","ENG":"Haha, my bad! We have TWO Ultimate Doomsday Weapons here!","TWN":"呵呵～我真是的！沒錯，有２個決戰兵器！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"우, 움직이지 마시라니까요! 이러다 고정장치가 망가져요!!","JPN":"う、動かないでくださいなのです！　固定装置が壊れますよ！！","ENG":"P-please stop moving! You'll break everything!!","TWN":"不…不要亂動啦！固定裝置會壞掉啦！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"미리 말해 두네만, 지금이라도 회사로 복귀해도 괜찮네.","JPN":"先に言っておくが、今からでも会社に戻ってきてもいいんだぞ。","ENG":"Just to be clear, it's not too late to return to the office now.","TWN":"我先把話說在前頭，就算你現在想打道回府也沒關係。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네도 봤다시피, 상대는 시윤 군을 제압할 수 있을 만큼 위험한 자들이니까.","JPN":"君も見たとおリ、相手はアキヤマ君を制圧できるほど危険な連中だ。","ENG":"As you have seen, they're formidable enough to overpower Shiyoon.","TWN":"畢竟你也有看到，那些傢伙是可以壓制時雲的危險人物。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그야 당연하잖아. 가야지.","JPN":"もう決めたの。行かなくちゃ。","ENG":"I think you know my answer. I'm going.","TWN":"當然要去囉！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"손 놓고 기다리만 하는 건 질색이야.","JPN":"黙って待ってるだけなんて嫌。","ENG":"There's nothing I hate more than sitting around watching.","TWN":"我最討厭的就是毫無作為的空等。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"고마워, 사장님. 선배를 구할 방법을 알려줘서.","JPN":"ありがとう、社長。先輩を救う方法を教えてくれて。","ENG":"Thanks, Boss. Now I know how I can save him.","TWN":"老闆，謝謝你告訴我救出前輩的方法。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이 전투복도 그렇고, 최근엔 계속 신세만 지네. ","JPN":"この戦闘服もそうだし、最近はずっとお世話になってばかりだね。","ENG":"I keep owing you more favors, including this suit. ","TWN":"還有這套戰鬥裝，最近老是欠老闆人情呢！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아, 그렇지. 돌아오면 사장님한테도 컵라면 대접할게.","JPN":"あ、そうだ。戻ったら社長にも焼きそばパンを奢るね。","ENG":"Oh, I know. I'll get you a cup of noodles as well when I get back.","TWN":"有了！回去後我也請老闆吃碗泡麵吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아니, 잠깐. 사장님은 로봇이라서 라면은 못 먹으려나?","JPN":"いや、ちょっと待って。社長はロボットだからパンは食べられないかな？","ENG":"Then again… I guess you can't eat because you're a robot?","TWN":"不對，老闆是機器人，沒辦法吃泡麵吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하, 걱정말게나. 내 몸엔 미각 회로도 장착되어 있거든. ","JPN":"ハハ、心配するな。この体には味覚回路も装着されているのだ。","ENG":"Haha, don't worry. I'm outfitted with taste detection sensors. ","TWN":"哈哈～OK的～我體內有安裝味覺線路。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"미나 양이 끓여주는 라면이라면 절대로 포기할 수 없지. ","JPN":"ミナ君が買ってくれる焼きそばパンなら、何が何でも食べてやらないと。","ENG":"I'd never pass the opportunity to taste noodles you've prepared. ","TWN":"米娜親手幫我煮的泡麵當然要吃囉！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그럼 무사히 돌아오길 기다리겠네.","JPN":"それでは、無事に帰ってくるのを待っている。","ENG":"In any case, I hope you return safely.","TWN":"那我等你們平安回來！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"응. 맡겨 둬. 선배를 구해서 금방 돌아올 테니까.","JPN":"うん。任せておいて。先輩を見つけて、すぐ帰るから。","ENG":"Yeah. You can count on me. I'll bring back Shiyoon with me in no time.","TWN":"沒問題，等我把前輩救出來就馬上回去！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저도 여러분과 함께하겠어요.","JPN":"私も皆様とご一緒します。","ENG":"I will also join you.","TWN":"我也和你們一起去。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"학생회장?","JPN":"生徒会長？","ENG":"You will?","TWN":"會長？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하지만 위험할 텐데…….","JPN":"でも、かなり危険だと思うけど……","ENG":"But it's going to get dangerous…","TWN":"可是會很危險……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이번 사건에는 알렌 선생님과 레이 학생이 관련되어 있어요.","JPN":"今度の事件にはアレン先生とレイさんが関わっています。","ENG":"This incident involves both a faculty member and a student from the Academy.","TWN":"這次的事件艾倫老師和雷伊同學都牽涉其中，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미 총학생회장으로서, 저 역시 사태의 진상을 끝까지 추적해야 할 의무가 있습니다.","JPN":"アカデミー総生徒会の会長として、私も事件の真相を最後まで追跡する義務があります。","ENG":"As the Student President, I am obligated to get to the bottom of this.","TWN":"身為學院的學生會會長，我有義務要查明事情的真相。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"너무 걱정 마세요. 현역 태스크포스인 미나 양만큼은 아니지만 제 한 몸 정도는 충분히 지킬 수 있습니다.","JPN":"あまり心配しないでください。現役タスクフォースカンパニーのミナさんほどではありませんが、自分の体ぐらいは十分守れます。","ENG":"Don't worry. I may not be as capable as an active-duty TASKFORCE member like you, but I can keep myself safe at the very least.","TWN":"你們放心，雖然我不像現役特遣隊成員米娜那樣厲害，但保護自己是沒問題的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나, 나도! 무섭긴 하지만 또 미나만 놔두고 가긴 싫어!","JPN":"わ、私も！　怖いけど、ミナちゃんだけ置いて行くなんてできない！","ENG":"M-me too! I'd be lying if I said I'm not scared, but I don't want to leave you all alone again!","TWN":"還…還有我！雖然有點怕怕的，但我不能丟下米娜一個人！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"좋아! 그럼 대장은 여기서 제일 강한 내가 맡는 거겠지?","JPN":"よし！　じゃあ隊長はこの中で一番強い私がやればいいんだよね？","ENG":"Great! Then I guess I'll get to be the leader here, since I'm the strongest, eh?","TWN":"好！那隊長當然就由最強的我來擔任囉！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"아니.","JPN":"いや。","ENG":"Nope.","TWN":"不行。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아닌데.","JPN":"ダメだね。","ENG":"No.","TWN":"不能。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아닙니다.","JPN":"いいえ。","ENG":"I'm afraid not.","TWN":"不可以。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"……고마워, 다들.","JPN":"……ありがとう、みんな。","ENG":"…Thank you, everyone.","TWN":"……謝謝你們。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"가자. 선배를 찾으러.","JPN":"行こう、先輩を探しに。","ENG":"Let's get going then. It's time to find Shiyoon.","TWN":"走吧！我們去找前輩吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};